module top_module(
    input [3:0] data_in,
    input [1:0] sel,
    input clk,
    input rst,
    output reg out
);always @(posedge clk or negedge rst) begin
    if (rst == 1'b0) begin
        out <= 1'b0;
    end else begin
        case (sel)
            2'b00: out <= data_in[0];
            2'b01: out <= data_in[1];
            2'b10: out <= data_in[2];
            2'b11: out <= data_in[3];
        endcase
    end
end

endmodule
